xinshengCustomCss:
/* ================= 基础重置 ================= */
.xt-root * { box-sizing: border-box !important; }
.xt-header, .xt-badge, .xt-grid, .xt-section, .xt-toggle, .xt-action-1, .xt-action-2 { display: none !important; }
.xt-text { 
    margin: 0 !important; 
    padding: 0 !important; 
    border: none !important; 
    display: block !important; 
    box-shadow: none !important; 
    white-space: pre-wrap !important; 
    outline: none !important; 
    background: transparent !important; 
    border-radius: 0 !important; 
}

/* ================= 根容器 ================= */
.xt-root {
    width: 100% !important;
    max-width: 400px !important;
    height: 650px !important;
    background: transparent !important; 
    position: relative !important;
    margin: 0 auto !important;
    overflow: visible !important; 
    font-family: 'Times New Roman', Georgia, serif !important;
}

/* ================= 1-3. 缩小的侧边索引贴 ================= */
.xt-text:nth-of-type(1),
.xt-text:nth-of-type(2),
.xt-text:nth-of-type(3) {
    position: absolute !important;
    left: 4px !important;
    width: 20px !important;
    height: 60px !important;
    border-radius: 4px 0 0 4px !important;
    writing-mode: vertical-rl !important;
    text-orientation: mixed !important;
    text-align: center !important;
    padding-right: 6px !important;
    font-size: 8px !important;
    letter-spacing: 1px !important;
    color: #3f444a !important;
    box-shadow: -2px 2px 4px rgba(0,0,0,0.06) !important;
    z-index: 1 !important;
    font-family: Arial, Helvetica, sans-serif !important;
}
.xt-text:nth-of-type(1) { top: 70px !important; background-color: #d4e4f4 !important; } 
.xt-text:nth-of-type(2) { top: 150px !important; background-color: #c4d4e4 !important; }
.xt-text:nth-of-type(3) { top: 230px !important; background-color: #b4c4d4 !important; }

/* ================= 4. 加宽的主体底板 ================= */
.xt-text:nth-of-type(4) {
    position: absolute !important;
    left: 20px !important;
    top: 20px !important;
    width: 340px !important;
    height: 610px !important;
    background-color: #fafcff !important; 
    border-radius: 2px !important;
    box-shadow: 8px 15px 30px rgba(0,0,0,0.08), 0 0 3px rgba(0,0,0,0.03) !important;
    z-index: 2 !important;
}
/* 档案编号 */
.xt-text:nth-of-type(4)::before {
    content: 'No. 7749-X' !important;
    position: absolute !important;
    top: 15px !important;
    right: 25px !important;
    font-family: 'Courier New', Courier, monospace !important;
    font-size: 10px !important;
    color: rgba(0,0,0,0.15) !important;
    letter-spacing: 1px !important;
}
/* 大型复古印章水印 */
.xt-text:nth-of-type(4)::after {
    content: ' MiMi\A xinsheng' !important;
    white-space: pre !important;
    text-align: center !important;
    position: absolute !important;
    top: 55% !important;
    left: 45% !important;
    transform: translate(-50%, -50%) rotate(-25deg) !important;
    font-size: 22px !important;
    line-height: 1.4 !important;
    color: rgba(131, 151, 181, 0.06) !important; 
    font-family: 'Courier New', Courier, monospace !important;
    font-weight: bold !important;
    letter-spacing: 2px !important;
    border: 4px double rgba(131, 151, 181, 0.06) !important;
    padding: 15px 20px !important;
    border-radius: 8px !important;
    pointer-events: none !important;
    z-index: 1 !important;
}

/* ================= 5. 右侧三角封口 (封头) ================= */
.xt-text:nth-of-type(5) {
    position: absolute !important;
    left: 190px !important; 
    top: 20px !important;
    width: 0 !important;
    height: 0 !important;
    border-top: 305px solid transparent !important;
    border-bottom: 305px solid transparent !important;
    border-right: 170px solid #eef4fa !important; 
    filter: drop-shadow(-3px 0 3px rgba(0,0,0,0.03)) !important;
    z-index: 3 !important;
}

/* ================= 6. 复古邮戳 ================= */
.xt-text:nth-of-type(6) {
    position: absolute !important;
    left: 30px !important;
    top: 40px !important;
    width: 65px !important;
    height: 65px !important;
