    z-index: 4 !important;
    font-family: 'Courier New', Courier, monospace !important;
}
.xt-text:nth-of-type(6)::before {
    content: '' !important; position: absolute !important;
    left: 5px !important; right: 5px !important; top: 22px !important; height: 1px !important;
    background: rgba(131, 151, 181, 0.3) !important;
}
.xt-text:nth-of-type(6)::after {
    content: '' !important; position: absolute !important;
    left: 5px !important; right: 5px !important; bottom: 22px !important; height: 1px !important;
    background: rgba(131, 151, 181, 0.3) !important;
}

/* ================= 7. 火漆印章 (自定义图片) ================= */
.xt-text:nth-of-type(7) {
