xinshengCustomCss:
/* 0. 彻底重置 */
.xt-root * { box-sizing: border-box !important; }
.xt-header, .xt-badge, .xt-grid, .xt-section, .xt-toggle, .xt-action-1, .xt-action-2 { display: none !important; }
.xt-text { margin: 0 !important; padding: 0 !important; background: transparent !important; border: none !important; display: block !important; box-shadow: none !important; white-space: pre-wrap !important; }

/* 1. 根容器与 CSS 变量状态机 (打孔胶圈使用随动背景，无限延伸绝不空白) */
.xt-root {
    background-color: #ebf6f7 !important; /* 薄荷白主背景 */
    background-image: 
        linear-gradient(to bottom, #c1e6e4 2px, transparent 2px, transparent 46px, #c1e6e4 46px),
        radial-gradient(circle at 16px 24px, #705854 4px, transparent 5px),
        linear-gradient(to right, #f8fbfb 31px, #c1e6e4 32px, transparent 32px) !important;
    background-position: 10px 0, 0 0, 0 0 !important;
    background-size: 12px 48px, 32px 48px, 100% 100% !important;
    background-repeat: repeat-y, repeat-y, no-repeat !important;
    background-attachment: local, local, local !important; /* 跟随内容无限滚动延伸！ */
    margin-top: 30px !important;
    padding: 0 20px 40px 45px !important; 
    height: 720px !important; 
    overflow-y: auto !important; overflow-x: hidden !important;
    border-radius: 12px 20px 20px 12px !important;
    font-family: "SF Pro Display", -apple-system, BlinkMacSystemFont, Arial, sans-serif !important;
    box-shadow: 15px 15px 40px rgba(193,230,228,0.08), inset -5px 0 20px rgba(193,230,228,0.03), 0 0 0 1px #c1e6e4 !important;
    position: relative !important;
    /* 默认状态：显示宠物页，隐藏Char页 */
    --show-pet: block;
    --show-char: none;
    --tab-pet-bg: #ffffff;
    --tab-pet-col: #705854;
    --tab-char-bg: #f8fbfb;
    --tab-char-col: #a49e99;
}
/* 悬停切换魔法 */
.xt-root:has(.xt-text:nth-of-type(2):hover), .xt-root:has(.xt-text:nth-of-type(n+23):hover) {
    --show-pet: none;
    --show-char: block;
    --tab-pet-bg: #f8fbfb;
    --tab-pet-col: #a49e99;
    --tab-char-bg: #ffffff;
    --tab-char-col: #705854;
}
.xt-root::-webkit-scrollbar { width: 4px !important; }
.xt-root::-webkit-scrollbar-thumb { background: #c1e6e4 !important; border-radius: 2px !important; }

